// Solution
function findMedian(arr) {
    if (arr.length === 0) {
        return -1;
    }
    arr.sort(function(a, b) {
        return a - b;
    });
    if (arr.length % 2 === 1) {
        return arr[Math.floor(arr.length / 2)];
    } else {
        return (arr[Math.floor(arr.length / 2)] + arr[Math.floor(arr.length / 2) - 1]) / 2;
    }
}
